import React, { useState } from "react";
import { useDispatch } from "react-redux";

import {
  Box,
  Heading,
  Text,
  Checkbox,
  FormControl,
  Button,
  UnorderedList,
  ListItem,
  Flex,
} from "@chakra-ui/react";

import { useNavigate } from "react-router-dom";
import { changeRole } from "../../Redux/TeacherReducer/action";

const TeachVerify = () => {
  const navigate = useNavigate();
  const dispatch = useDispatch();

  const [accepted, setAccepted] = useState(false);

  const user = JSON.parse(localStorage.getItem("user"));

  const teacher = () => {
    if (!accepted) return alert("Please accept terms first!");

    dispatch(changeRole("teacher", user.userId));
    navigate("/TeacherDashboard");
  };

  return (
    <Box bg="#f7f9fa" minH="100vh" display="flex" alignItems="center">
      <Box
        maxW="700px"
        mx="auto"
        w="100%"
        bg="white"
        p={8}
        borderRadius="lg"
        boxShadow="lg"
      >
        {/* HEADER */}
        <Box textAlign="center" mb={6}>
          <Heading size="lg" mb={2}>
            Become an Instructor
          </Heading>
          <Text color="gray.600">
            Read and accept the terms to start teaching on our platform
          </Text>
        </Box>

        {/* TERMS */}
        <Box
          maxH="250px"
          overflowY="auto"
          pr={2}
          mb={6}
        >
          <UnorderedList spacing={3}>
            <ListItem>
              You must be at least <b>18 years old</b> to register as a teacher.
            </ListItem>
            <ListItem>
              You must have the required <b>skills and expertise</b> to teach your courses.
            </ListItem>
            <ListItem>
              You must provide <b>accurate and complete information</b>.
            </ListItem>
            <ListItem>
              You agree to follow platform rules and maintain course quality.
            </ListItem>
          </UnorderedList>
        </Box>

        {/* CHECKBOX */}
        <FormControl mb={6}>
          <Flex align="center" gap={3}>
            <Checkbox
              size="lg"
              colorScheme="purple"
              onChange={(e) => setAccepted(e.target.checked)}
            />
            <Text fontSize="sm">
              I agree to all terms and conditions
            </Text>
          </Flex>
        </FormControl>

        {/* BUTTON */}
        <Button
          w="100%"
          bg="#A435F0"
          color="white"
          py={6}
          fontSize="md"
          borderRadius="md"
          _hover={{ bg: "#8710d8" }}
          _disabled={{ bg: "gray.300", cursor: "not-allowed" }}
          isDisabled={!accepted}
          onClick={teacher}
        >
          Continue as Instructor
        </Button>
      </Box>
    </Box>
  );
};

export default TeachVerify;
